INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-6f0ba476-moex-00064', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-114-34c7f7f6', 'sub-elementary-6f0ba476-02', NULL, 'single_choice', '「從沒有人因為缺乏香料而死，但卻有成千上萬的人——包括掠奪者和受害者為它而死。控 制豆蔻、肉桂和黑胡椒等重要香料交易而產生的私欲，使歐洲商業強權犯下許多暴行。然而， 若沒有香料貿易帶來的財富，恐怕根本不會發生文藝復興。大仲馬曾說：『在香料刺激造成 的興奮影響之下，智能的表現達到高峰。提香的畫作是否香料的功勞？我忍不住要這麼想。』」 根據上文，關於香料的敘述，不符合文意的是：', '["歐洲商業強權爭奪香料控制權時，曾殘忍的傷害許多人", "香料是生活必需品，不可缺乏，所以引發激烈的爭奪戰", "香料貿易所帶來的財富，有助歐洲文藝復興運動的推動", "大仲馬認為提香的繪畫成就，可能受到香料刺激的影響"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:37+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "510", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00065', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-114-34c7f7f6', 'sub-elementary-6f0ba476-02', NULL, 'single_choice', '「古代文人多年以來，受傳統影響，最愛講道理，不談事功。在帝制下的臣相賢士，只是向 君王個人盡責，肯不肯多做事沒大關係。因此，老成持重，乃是最高的大臣風範。王安石這 位首相不來這一套，他明知『遠世有百善，一疵惡皆歸，就求無所得，猶以好名譏』，還是 勉力而為，八年新政雖說未竟，但他那種開創、喜事，與愛國精神，是不該抹殺的。」 根據上文，下列選項何者最接近作者的觀點？', '["肯定王安石勇於任事，能夠以新政實踐理想", "文人只要盡責愛國，尊重傳統，就能博得美名", "文人多以建功立業為尚，展現老成持重的大臣風範", "稱許王安石明知新政有瑕疵，仍勉力而為的開創精神"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:37+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "510", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00066', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-114-34c7f7f6', 'sub-elementary-6f0ba476-02', NULL, 'single_choice', '「叔本華說過這樣的話：要估定人的偉大，則精神上的大和體格上的大，那法則完全相反。 後者距離愈遠即愈小，前者卻見得愈大。正因為近則愈小，而且愈看見缺點和創傷，所以他 就和我們一樣，不是神道，不是妖怪，不是異獸。他仍然是人，不過如此。但也惟其如此， 所以他是偉大的人。戰士戰死了的時候，蒼蠅們所首先發現的是他的缺點和傷痕，嘬著，營 營地叫著，以為得意，以為比死了的戰士更英雄。但是戰士已經戰死了，不再來揮去他們。 於是乎蒼蠅們即更其營營地叫，自以為倒是不朽的聲音，因為它們的完全，遠在戰士之上。 的確的，誰也沒有發現過蒼蠅們的缺點和創傷。然而，有缺點的戰士終竟是戰士，完美的蒼 蠅也終竟不過是蒼蠅。」 根據上文，下列選項最接近作者旨趣的是：', '["全文譏刺偉人仍不免有瑕疵，而如蒼蠅般的小人亦有價值", "戰士之所以偉大，是因為具備「精神上的大」與「體格上的大」", "「精神上的大」，距離越近越能看見缺點和創傷，所以偉人和凡人一樣", "「體格上的大」，距離越遠所見越小，意謂局外人對事物的觀察將更細微"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:37+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "510", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00067', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-114-34c7f7f6', 'sub-elementary-6f0ba476-02', NULL, 'single_choice', '「三國時期，晉、吳相爭，吳國大將陸抗生了一場大病，對手晉國大將羊祜善於用兵，且兼 通醫道，派人送了一帖藥給陸抗。陸抗毫不猶疑將藥服用，部屬勸止，擔心羊祜的藥是否可 靠。陸抗說：『羊祜豈鴆人者。』意思是羊祜縱然在沙場與我為敵，但『藥』就是『藥』。 沙場爭馳是一回事，但醫人是另一回事。」 根據上文，下列選項何者最符合文意？', '["陸抗跟羊祜本來就是好朋友", "人道主義應該超越敵我意識", "兩軍對陣不是你死就是我活", "羊祜送藥給陸抗是通敵行為"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:37+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "510", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00068', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-114-34c7f7f6', 'sub-elementary-6f0ba476-02', NULL, 'single_choice', '頃歲孫莘老識歐陽文忠公，嘗乘閒以文字問之，云：「無它術，唯勤讀書而多為之，自工。 世人患作文字少，又嬾讀書，每一篇出，即求過人，如此少有至者。疵病不必待人指擿，多 作自能見之。」此公以其嘗試者告人，故尤有味。（《東坡志林》） 文中歐陽脩所言，下列選項何者最符合文意？', '["勤讀各種書籍，自然能寫得出佳作", "世人讀書太少，故難掌握撰文訣竅", "只期待每篇盡屬佳作，則不免得罪人", "勤讀書多寫作，便能知自己文章問題"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:37+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "510", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00069', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-114-34c7f7f6', 'sub-elementary-6f0ba476-02', NULL, 'single_choice', '朱熹〈觀書有感〉：「半畝方塘一鑑開，天光雲影共徘徊。問渠那得清如許？為有源頭活 水來。」 根據上文，下列選項何者最符合文意？', '["將天光雲影加以擬人化，表現雨過初晴的心境", "藉著天機盎然景象，寄託作者悲天憫人的情懷", "藉自然現象為喻，說明讀書可使心靈更加清明", "以所見的自然景象，寄託田園隱居的愉悅心情"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:37+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "510", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00070', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-114-34c7f7f6', 'sub-elementary-6f0ba476-02', NULL, 'single_choice', '人為萬物之靈。性相近，習相遠。與齊人居，不能不齊言也；與楚人居，不能不楚言也。入 芝蘭之室，久而不聞其香，與之俱化矣；入鮑魚之肆，久而不聞其臭，亦與之俱化矣。故曰 一方水土一方人，又曰跟著好人學好人，跟著師婆跳假神。（李光庭《鄉言解頤》） 下列選項，何者最符合上文中對「人」的看法？', '["人具有避惡向善的本性", "人擁有分辨好壞的能力", "人具備改變風俗的能力", "人自然而然受環境影響"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:37+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "510", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00071', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-114-34c7f7f6', 'sub-elementary-6f0ba476-02', NULL, 'single_choice', '「中國書畫收藏史中最著名的『留白煞星』，恐怕就是好大喜功，自封『十全老人』的乾隆 皇帝。他的收藏慾望遠勝其藝術品味，往往在名作上胡亂『塗鴉』。王羲之一張僅二十八字 的《快雪時晴帖》，乾隆卻一口氣蓋上一百七十個印章。在黃公望的《富春山居圖》，他幾 乎將畫圖留白的地方都填滿文字，更把字句直接寫在山石之上，整個富有靈氣的作品毀於一 旦。可幸的是因為乾隆的藝術水平不高，竟然誤把《富》的贗本（子明卷）視為真品，反而 將他同時擁有的真跡（無用師卷）當作贗品，束之高閣並且未題一字。這幅不朽的傳世名作 因此倖免於難，這樣的保存下來。」 根據上文，下列選項何者符合文意？', '["「留白煞星」是收藏家喜歡在留白處蓋印或題字，導致畫面受到破壞", "乾隆為避免破壞留白處，在山石上直接題字，成為特有的藝術重置法", "《富春山居圖》有許多贗本，乾隆將無用師卷保存得宜，只在子明卷題字，不忍破壞真蹟", "因為乾隆有意將真本束之高閣，並且保存得宜，後人才得以見到《富春山居圖》傳世名作"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:37+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "510", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00072', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-114-34c7f7f6', 'sub-elementary-6f0ba476-02', NULL, 'single_choice', '《楚辭・漁父》說：「滄浪之水清兮，可以濯我纓；滄浪之水濁兮，可以濯我足。」下列選 項何者最貼近文中所傳達的處世態度？', '["隨波逐流，明哲保身", "千鈞為輕，蟬翼為重", "避世歸隱，方為正途", "擇善固執，各從其志"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:37+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "510", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00073', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-114-34c7f7f6', 'sub-elementary-6f0ba476-02', NULL, 'single_choice', '「回來隔離第一天，我坐在窗前看馬路上的活動，發現大部分的車子都是白色的，不知道怎 麼回事。公車的車頂有各種式樣，有天窗的，有圓孔的。騎摩托車的人則像演員一樣，用肢 體表演。我覺得自己就好像剛買回來的金魚，還不能倒入新的水域中，於是和著一些舊的水 裝在袋裡，隔著袋子在看著新世界，而尚不屬於它。」 根據上文，下列選項何者最貼近作者的感受？', '["面對未知未來感到徬徨", "讚嘆市民擁有豐沛活力", "感覺孤獨想要家人陪伴", "對於所見充滿隔閡疑惑"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:37+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "510", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL)
